mapper.insert:
/*
	 토론 댓글 등록
	 ForumCmntDAO.insertCmnt
*/
INSERT INTO TB_LMS_DSCS_CMNT (
	DSCS_CMNT_ID
	, DSCS_ID
	, ATCL_ID
	, RSPNS_REQYN
	, UP_CMNT_ID
	, ATCL_CMNT_CTS
	, EMTICN_NO
	, STD_ID
	, RGTRNM
	, RGTR_ID
	, FRST_INQ_DTTM
	, MDFR_ID
	, MOD_DTTM
	, DELYN
	, CMNT_CTS_LEN
) VALUES (
	#{cmntSn}
	, #{forumCd}
	, #{atclSn}
	, #{ansReqYn}
	, #{parCmntSn}
	, #{cmntCts}
	, #{emoticonNo}
	, #{stdNo} 
	, #{regNm}
	, #{rgtrId}
	, FN_DTTM()
	, #{mdfrId}
	, FN_DTTM()
	, 'N'
	, #{cmntCtsLen}
)

mapper.update:
/*
	 토론방 댓글 수정
	 ForumCmntDAO.updateCmnt
*/
UPDATE TB_LMS_DSCS_CMNT
SET ATCL_CMNT_CTS = #{cmntCts}
	, CMNT_CTS_LEN = #{cmntCtsLen}
	, RSPNS_REQYN = #{ansReqYn}
	, MOD_DTTM = FN_DTTM()
WHERE DSCS_CMNT_ID = #{cmntSn}
